<style>
    .planning-page,.planning-page *{box-sizing:border-box}
    .planning-page{color:var(--onyx-text,#f5f7fa);display:grid;font-family:Poppins,system-ui,sans-serif;font-size:12px;gap:14px;width:100%}
    .planning-header,.planning-card,.planning-panel{background:linear-gradient(180deg,rgba(255,255,255,.035),rgba(255,255,255,.012)),var(--onyx-surface,#101923);border:1px solid rgba(255,106,0,.18);border-radius:0;box-shadow:0 10px 28px rgba(0,0,0,.22)}
    .planning-header{align-items:center;display:flex;gap:14px;justify-content:space-between;padding:16px}
    .planning-title{align-items:center;display:flex;gap:12px;min-width:0}.planning-icon{align-items:center;background:var(--onyx-accent,#ff6a00);color:#050506;display:inline-flex;flex:0 0 38px;height:38px;justify-content:center;width:38px}
    .planning-header h1{color:#fff;font-size:18px;font-weight:900;line-height:1.15;margin:0 0 3px}.planning-muted{color:var(--onyx-muted,#8d99a8);font-size:11px;font-weight:700;line-height:1.45}
    .planning-actions{align-items:center;display:flex;flex-wrap:wrap;gap:8px}.planning-button{align-items:center;background:var(--onyx-accent,#ff6a00);border:1px solid var(--onyx-accent,#ff6a00);color:#050506;cursor:pointer;display:inline-flex;font:inherit;font-size:11px;font-weight:900;gap:8px;justify-content:center;min-height:36px;padding:0 12px;text-decoration:none;text-transform:uppercase;white-space:nowrap}.planning-button.secondary{background:rgba(255,255,255,.025);border-color:rgba(255,106,0,.2);color:var(--onyx-text,#f5f7fa)}
    .planning-grid{display:grid;gap:12px;grid-template-columns:repeat(4,minmax(0,1fr))}.planning-card{min-width:0;padding:13px}.planning-card span,.planning-field label,.planning-table th{color:var(--onyx-muted,#8d99a8);display:block;font-size:10px;font-weight:900;letter-spacing:.5px;text-transform:uppercase}.planning-card strong{color:#fff;display:block;font-size:18px;font-weight:900;margin-top:6px;overflow-wrap:anywhere}
    .planning-split{display:grid;gap:12px;grid-template-columns:minmax(0,1.15fr) minmax(300px,.85fr)}.planning-panel{padding:15px}.planning-panel-head{align-items:center;border-bottom:1px solid rgba(255,255,255,.06);display:flex;gap:10px;justify-content:space-between;margin-bottom:13px;padding-bottom:11px}.planning-panel h2{color:#fff;font-size:13px;font-weight:900;margin:0;text-transform:uppercase}
    .planning-table-wrap{overflow-x:auto}.planning-table{border-collapse:collapse;min-width:860px;width:100%}.planning-table th,.planning-table td{border-bottom:1px solid rgba(255,255,255,.06);font-size:12px;padding:10px;text-align:left;vertical-align:middle}.planning-table td{color:var(--onyx-text,#f5f7fa);font-weight:650}.planning-table tbody tr:hover{background:rgba(255,106,0,.055)}.planning-table-title{color:#fff;display:block;font-size:12px;font-weight:900;margin-bottom:3px}.planning-table-title a{color:#fff;text-decoration:none}
    .planning-badge{border:1px solid rgba(255,106,0,.32);color:#d8d8de;display:inline-flex;font-size:10px;font-weight:900;padding:5px 7px;text-transform:uppercase;white-space:nowrap}.planning-badge.success{border-color:rgba(143,240,195,.32);color:#8ff0c3}.planning-badge.warning{border-color:rgba(255,210,122,.32);color:#ffd27a}.planning-badge.danger{border-color:rgba(255,138,138,.32);color:#ff8a8a}
    .planning-alert{background:linear-gradient(180deg,rgba(255,255,255,.035),rgba(255,255,255,.012)),var(--onyx-surface,#101923);border:1px solid rgba(255,106,0,.18);color:#fff;font-size:12px;font-weight:800;padding:10px 12px}.planning-alert.success{border-color:rgba(143,240,195,.28);color:#8ff0c3}.planning-alert.warning{border-color:rgba(255,210,122,.28);color:#ffd27a}.planning-alert.danger{border-color:rgba(255,138,138,.28);color:#ff8a8a}
    .planning-form{display:grid;gap:12px;grid-template-columns:repeat(4,minmax(0,1fr))}.planning-field{display:grid;gap:6px;min-width:0}.planning-field.full{grid-column:1/-1}.planning-field.double{grid-column:span 2}.planning-field input,.planning-field select,.planning-field textarea{background:#0b141e;border:1px solid rgba(255,106,0,.18);color:#fff;font:inherit;font-size:12px;font-weight:700;min-height:38px;padding:8px 10px;width:100%}.planning-field textarea{min-height:82px;resize:vertical}.planning-field select option{background:#050506;color:#fff}
    .planning-progress{background:#071019;border:1px solid rgba(255,255,255,.08);height:8px;min-width:110px;overflow:hidden}.planning-progress span{background:var(--onyx-accent,#ff6a00);display:block;height:100%;max-width:100%}
    @media(max-width:1180px){.planning-grid,.planning-form,.planning-split{grid-template-columns:repeat(2,minmax(0,1fr))}}
    @media(max-width:720px){.planning-header{align-items:flex-start;flex-direction:column}.planning-grid,.planning-form,.planning-split{grid-template-columns:1fr}.planning-field.double{grid-column:1}.planning-button{width:100%}.planning-actions{align-items:stretch;width:100%}.planning-actions>*{flex:1 1 100%}}
</style>
